#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct Graph {
    int V;
    int **adj;
} Graph;

// Function to create a graph
Graph* createGraph(int V) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;
    graph->adj = (int**) malloc(V * sizeof(int*));
    for (int i = 0; i < V; i++) {
        graph->adj[i] = (int*) malloc(V * sizeof(int));
        for (int j = 0; j < V; j++) {
            graph->adj[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adj[u][v] = 1;
}

// Function to detect cycle in the graph
int hasCycle(Graph* graph) {
    int* indegree = (int*) malloc(graph->V * sizeof(int));
    for (int i = 0; i < graph->V; i++) {
        indegree[i] = 0;
    }
    for (int i = 0; i < graph->V; i++) {
        for (int j = 0; j < graph->V; j++) {
            if (graph->adj[i][j] == 1) {
                indegree[j]++;
            }
        }
    }
    int count = 0;
    int* queue = (int*) malloc(graph->V * sizeof(int));
    int front = 0, rear = -1;
    for (int i = 0; i < graph->V; i++) {
        if (indegree[i] == 0) {
            queue[++rear] = i;
        }
    }
    while (front <= rear) {
        int node = queue[front++];
        count++;
        for (int i = 0; i < graph->V; i++) {
            if (graph->adj[node][i] == 1) {
                indegree[i]--;
                if (indegree[i] == 0) {
                    queue[++rear] = i;
                }
            }
        }
    }
    free(indegree);
    free(queue);
    return count != graph->V;
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    Graph* graph = createGraph(V);
    for (int i = 0; i < E; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(graph, u-1, v-1);
    }
    if (hasCycle(graph)) {
        printf("Cycle detected\n");
    } else {
        printf("No cycle\n");
    }
    return 0;
}

